/**
 * PHASE 3 + 11: COMPLETE DATABASE SCHEMA WITH RLS POLICIES
 * 
 * Generated by: Senior Security Engineer + Database Engineer
 * Security Level: Enterprise
 * Encryption: AES-256-GCM for sensitive fields
 * Authentication: JWT + Row Level Security (RLS)
 * 
 * Run this SQL in Supabase SQL Editor to create all tables and policies.
 * 
 * SENSITIVE FIELDS REQUIRING ENCRYPTION:
 * - user_profile: phone_encrypted, pan_encrypted, aadhaar_encrypted
 * - invoices: encrypted_file_path (file content)
 * - documents: encrypted_file_path (file content)
 * - suppliers: supplier_contact_encrypted
 * 
 * QUERYABLE FIELDS (NO ENCRYPTION):
 * - Financial amounts (needed for reports/filtering)
 * - GST components (needed for tax calculations)
 * - Dates (needed for period filtering)
 * - Status fields (needed for filtering)
 */

-- ============================================================================
-- TABLE 1: USER PROFILES
-- ============================================================================

CREATE TABLE IF NOT EXISTS user_profiles (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- Supabase Auth User ID (foreign key to auth.users)
  auth_user_id UUID NOT NULL UNIQUE,
  
  -- Basic Information
  email VARCHAR(255) NOT NULL,
  business_name VARCHAR(255) NOT NULL,
  owner_name VARCHAR(255) NOT NULL,
  
  -- GSTIN (15-character GST ID) - UNENCRYPTED (needed for filtering)
  gstin VARCHAR(15) NOT NULL UNIQUE,
  
  -- Phone (ENCRYPTED)
  phone_encrypted VARCHAR(255), -- AES-256-GCM encrypted
  phone_iv VARCHAR(255),        -- Initialization vector for decryption
  
  -- Optional Government IDs (ENCRYPTED)
  pan_encrypted VARCHAR(255),   -- PAN card number
  pan_iv VARCHAR(255),
  aadhaar_encrypted VARCHAR(255), -- Aadhaar number
  aadhaar_iv VARCHAR(255),
  
  -- Preferred Language
  preferred_language VARCHAR(10) DEFAULT 'en',
  
  -- Bank Details (ENCRYPTED)
  bank_account_encrypted VARCHAR(255),
  bank_account_iv VARCHAR(255),
  bank_name VARCHAR(255),
  ifsc_code_encrypted VARCHAR(255),
  ifsc_code_iv VARCHAR(255),
  
  -- Account Status
  status VARCHAR(50) DEFAULT 'active',
  compliance_score INT DEFAULT 0, -- 0-100
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  last_login_at TIMESTAMP WITH TIME ZONE
);

-- Indexes for user lookup
CREATE INDEX idx_user_profiles_auth_user_id ON user_profiles(auth_user_id);
CREATE INDEX idx_user_profiles_gstin ON user_profiles(gstin);
CREATE INDEX idx_user_profiles_email ON user_profiles(email);

-- ============================================================================
-- TABLE 2: TAX RECORDS / RETURNS
-- ============================================================================

CREATE TABLE IF NOT EXISTS tax_records (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Financial Year & Assessment Year
  financial_year VARCHAR(20) NOT NULL, -- e.g., "2025-26"
  assessment_year VARCHAR(20),
  
  -- Tax Amounts (UNENCRYPTED - needed for reports/calculations)
  taxable_income DECIMAL(15, 2) NOT NULL DEFAULT 0,
  total_tax_amount DECIMAL(15, 2) NOT NULL DEFAULT 0,
  
  -- GST Components
  cgst_amount DECIMAL(15, 2) DEFAULT 0,
  sgst_amount DECIMAL(15, 2) DEFAULT 0,
  igst_amount DECIMAL(15, 2) DEFAULT 0,
  total_gst_amount DECIMAL(15, 2) DEFAULT 0,
  
  -- ITC (Input Tax Credit)
  eligible_itc DECIMAL(15, 2) DEFAULT 0,
  blocked_itc DECIMAL(15, 2) DEFAULT 0,
  claimed_itc DECIMAL(15, 2) DEFAULT 0,
  
  -- Filing Status
  status VARCHAR(50) DEFAULT 'draft', -- draft, filed, rejected, amended
  filing_date TIMESTAMP WITH TIME ZONE,
  
  -- Return Type
  return_type VARCHAR(50), -- GSTR-1, GSTR-2, GSTR-2B, etc.
  
  -- Notes
  notes TEXT,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_tax_records_user_id ON tax_records(user_id);
CREATE INDEX idx_tax_records_financial_year ON tax_records(financial_year);
CREATE INDEX idx_tax_records_status ON tax_records(status);

-- ============================================================================
-- TABLE 3: SUPPLIERS / VENDORS
-- ============================================================================

CREATE TABLE IF NOT EXISTS suppliers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Supplier Information
  supplier_name VARCHAR(255) NOT NULL,
  supplier_gstin VARCHAR(15) NOT NULL UNIQUE, -- UNENCRYPTED (needed for matching)
  
  -- Contact (ENCRYPTED)
  supplier_contact_encrypted VARCHAR(255),
  supplier_contact_iv VARCHAR(255),
  
  -- Risk Assessment
  risk_score INT DEFAULT 0, -- 0-100
  risk_level VARCHAR(50) DEFAULT 'low', -- low, medium, high
  error_count INT DEFAULT 0,
  total_invoices INT DEFAULT 0,
  
  -- Tax Classification
  hsn_code VARCHAR(8),
  product_category VARCHAR(255),
  
  -- Status
  status VARCHAR(50) DEFAULT 'active',
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_suppliers_user_id ON suppliers(user_id);
CREATE INDEX idx_suppliers_gstin ON suppliers(supplier_gstin);
CREATE INDEX idx_suppliers_risk_level ON suppliers(risk_level);

-- ============================================================================
-- TABLE 4: INVOICES
-- ============================================================================

CREATE TABLE IF NOT EXISTS invoices (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Invoice Details (UNENCRYPTED - needed for matching and filtering)
  invoice_number VARCHAR(255) NOT NULL,
  invoice_date DATE NOT NULL,
  
  -- Supplier Information (UNENCRYPTED - needed for matching)
  supplier_name VARCHAR(255) NOT NULL,
  supplier_gstin VARCHAR(15) NOT NULL,
  buyer_gstin VARCHAR(15) NOT NULL,
  
  -- Classification (UNENCRYPTED - needed for filtering)
  hsn_code VARCHAR(8),
  
  -- Amount Details (UNENCRYPTED - needed for calculations & reports)
  taxable_amount DECIMAL(15, 2) NOT NULL,
  cgst DECIMAL(15, 2) DEFAULT 0,
  sgst DECIMAL(15, 2) DEFAULT 0,
  igst DECIMAL(15, 2) DEFAULT 0,
  total_gst DECIMAL(15, 2) NOT NULL,
  grand_total DECIMAL(15, 2) NOT NULL,
  
  -- ITC Status
  itc_claimed DECIMAL(15, 2) DEFAULT 0,
  itc_blocked DECIMAL(15, 2) DEFAULT 0,
  itc_eligibility VARCHAR(50) DEFAULT 'eligible',
  
  -- Validation Status (UNENCRYPTED - needed for filtering)
  validation_status VARCHAR(50) DEFAULT 'pending', -- pending, valid, warning, critical
  validation_errors TEXT,
  
  -- Reconciliation Status
  gstr2b_status VARCHAR(50), -- matched, missing, mismatch, etc.
  gstr2b_match_details TEXT, -- JSON for comparison details
  
  -- File References
  original_filename VARCHAR(255),
  encrypted_file_path VARCHAR(255), -- Path in Supabase Storage
  encrypted_file_iv VARCHAR(255),   -- IV for file decryption
  file_mime_type VARCHAR(100),
  file_size_bytes INT,
  
  -- Metadata
  source VARCHAR(50) DEFAULT 'manual', -- manual, ocr, import, api
  notes TEXT,
  
  -- Status
  status VARCHAR(50) DEFAULT 'active', -- active, archived, disputed
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  
  -- Unique constraint: user cannot have duplicate invoice numbers
  CONSTRAINT unique_invoice_per_user UNIQUE(user_id, invoice_number)
);

CREATE INDEX idx_invoices_user_id ON invoices(user_id);
CREATE INDEX idx_invoices_invoice_number ON invoices(invoice_number);
CREATE INDEX idx_invoices_invoice_date ON invoices(invoice_date);
CREATE INDEX idx_invoices_supplier_gstin ON invoices(supplier_gstin);
CREATE INDEX idx_invoices_validation_status ON invoices(validation_status);
CREATE INDEX idx_invoices_gstr2b_status ON invoices(gstr2b_status);

-- ============================================================================
-- TABLE 5: TAX DOCUMENTS
-- ============================================================================

CREATE TABLE IF NOT EXISTS tax_documents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Document Classification
  document_type VARCHAR(100) NOT NULL, -- GST_RETURN, INVOICE_SUMMARY, TAX_CERTIFICATE, etc.
  document_name VARCHAR(255) NOT NULL,
  
  -- File References
  original_filename VARCHAR(255) NOT NULL,
  encrypted_file_path VARCHAR(255) NOT NULL, -- Path in Supabase Storage (encrypted)
  encrypted_file_iv VARCHAR(255) NOT NULL,   -- IV for file decryption
  file_mime_type VARCHAR(100),
  file_size_bytes INT,
  
  -- Metadata
  description TEXT,
  financial_year VARCHAR(20),
  tags VARCHAR(255), -- Comma-separated
  
  -- Status
  status VARCHAR(50) DEFAULT 'active', -- active, archived, pending_review
  is_verified BOOLEAN DEFAULT FALSE,
  verified_by UUID, -- ID of verifying user (admin)
  verified_at TIMESTAMP WITH TIME ZONE,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_tax_documents_user_id ON tax_documents(user_id);
CREATE INDEX idx_tax_documents_document_type ON tax_documents(document_type);
CREATE INDEX idx_tax_documents_financial_year ON tax_documents(financial_year);

-- ============================================================================
-- TABLE 6: GSTR-2B RECORDS
-- ============================================================================

CREATE TABLE IF NOT EXISTS gstr2b_records (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Record from Government (GSTR-2B)
  invoice_number VARCHAR(255) NOT NULL,
  supplier_name VARCHAR(255) NOT NULL,
  supplier_gstin VARCHAR(15) NOT NULL, -- UNENCRYPTED (needed for matching)
  
  -- Classification
  hsn_code VARCHAR(8),
  
  -- Amounts (UNENCRYPTED - needed for matching)
  taxable_amount DECIMAL(15, 2),
  cgst DECIMAL(15, 2),
  sgst DECIMAL(15, 2),
  igst DECIMAL(15, 2),
  total_gst DECIMAL(15, 2),
  grand_total DECIMAL(15, 2),
  
  -- Reconciliation
  matched_with_invoice_id UUID REFERENCES invoices(id) ON DELETE SET NULL,
  match_status VARCHAR(50), -- matched, unmatched, mismatch
  
  -- Upload Information
  gstr2b_upload_id UUID,
  upload_date DATE,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  
  CONSTRAINT unique_gstr2b_per_user UNIQUE(user_id, invoice_number, supplier_gstin)
);

CREATE INDEX idx_gstr2b_records_user_id ON gstr2b_records(user_id);
CREATE INDEX idx_gstr2b_records_invoice_number ON gstr2b_records(invoice_number);
CREATE INDEX idx_gstr2b_records_supplier_gstin ON gstr2b_records(supplier_gstin);
CREATE INDEX idx_gstr2b_records_match_status ON gstr2b_records(match_status);

-- ============================================================================
-- TABLE 7: RECONCILIATION RESULTS
-- ============================================================================

CREATE TABLE IF NOT EXISTS reconciliation_results (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Reconciliation Details
  invoice_id UUID REFERENCES invoices(id) ON DELETE CASCADE,
  gstr2b_record_id UUID REFERENCES gstr2b_records(id) ON DELETE CASCADE,
  
  -- Matching Result
  status VARCHAR(100) NOT NULL, -- matched, missing_in_gstr2b, gstin_mismatch, hsn_mismatch, tax_mismatch, duplicate_invoice, supplier_error
  
  -- Risk Assessment
  risk_level VARCHAR(50) DEFAULT 'low', -- low, medium, high
  potential_loss DECIMAL(15, 2) DEFAULT 0, -- Potential ITC loss
  confidence_score INT DEFAULT 0, -- 0-100
  
  -- Discrepancy Details
  discrepancy_details TEXT, -- JSON describing the mismatch
  
  -- Resolution
  resolved BOOLEAN DEFAULT FALSE,
  resolution_notes TEXT,
  resolved_at TIMESTAMP WITH TIME ZONE,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_reconciliation_results_user_id ON reconciliation_results(user_id);
CREATE INDEX idx_reconciliation_results_status ON reconciliation_results(status);
CREATE INDEX idx_reconciliation_results_risk_level ON reconciliation_results(risk_level);
CREATE INDEX idx_reconciliation_results_resolved ON reconciliation_results(resolved);

-- ============================================================================
-- TABLE 8: AUDIT LOGS
-- ============================================================================

CREATE TABLE IF NOT EXISTS audit_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID REFERENCES user_profiles(id) ON DELETE SET NULL,
  
  -- Action Details
  action VARCHAR(100) NOT NULL, -- LOGIN, LOGOUT, CREATE_INVOICE, UPDATE_INVOICE, DELETE_INVOICE, UPLOAD_FILE, DOWNLOAD_FILE, etc.
  resource_type VARCHAR(100), -- invoice, document, tax_record, etc.
  resource_id UUID,
  
  -- Changes (for update/delete operations)
  old_values TEXT, -- JSON
  new_values TEXT, -- JSON
  
  -- Request Metadata
  ip_address VARCHAR(50),
  user_agent TEXT,
  api_endpoint VARCHAR(255),
  http_method VARCHAR(10),
  http_status_code INT,
  
  -- Status
  status VARCHAR(50), -- success, failure, warning
  error_message TEXT,
  
  -- Timestamp
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_audit_logs_user_id ON audit_logs(user_id);
CREATE INDEX idx_audit_logs_action ON audit_logs(action);
CREATE INDEX idx_audit_logs_created_at ON audit_logs(created_at DESC);
CREATE INDEX idx_audit_logs_resource ON audit_logs(resource_type, resource_id);

-- ============================================================================
-- TABLE 9: NOTIFICATIONS
-- ============================================================================

CREATE TABLE IF NOT EXISTS notifications (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Notification Details
  title VARCHAR(255) NOT NULL,
  message TEXT NOT NULL,
  type VARCHAR(50) DEFAULT 'info', -- info, success, warning, danger, itc_alert
  
  -- Related Resource (optional)
  related_resource_type VARCHAR(100),
  related_resource_id UUID,
  
  -- Status
  is_read BOOLEAN DEFAULT FALSE,
  read_at TIMESTAMP WITH TIME ZONE,
  
  -- Dismissal
  is_dismissed BOOLEAN DEFAULT FALSE,
  dismissed_at TIMESTAMP WITH TIME ZONE,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_notifications_user_id ON notifications(user_id);
CREATE INDEX idx_notifications_is_read ON notifications(is_read);
CREATE INDEX idx_notifications_type ON notifications(type);

-- ============================================================================
-- TABLE 10: SESSIONS
-- ============================================================================

CREATE TABLE IF NOT EXISTS sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  
  -- User relationship
  user_id UUID NOT NULL REFERENCES user_profiles(id) ON DELETE CASCADE,
  
  -- Session Token
  token_hash VARCHAR(255) NOT NULL UNIQUE, -- SHA-256 hash of JWT (for security)
  
  -- Session Metadata
  ip_address VARCHAR(50),
  user_agent TEXT,
  device_name VARCHAR(255),
  is_active BOOLEAN DEFAULT TRUE,
  
  -- Expiration
  expires_at TIMESTAMP WITH TIME ZONE NOT NULL,
  
  -- Timestamps
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  last_activity_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

CREATE INDEX idx_sessions_user_id ON sessions(user_id);
CREATE INDEX idx_sessions_is_active ON sessions(is_active);
CREATE INDEX idx_sessions_expires_at ON sessions(expires_at);

-- ============================================================================
-- ROW LEVEL SECURITY (RLS) POLICIES
-- ============================================================================

-- Enable RLS on all tables
ALTER TABLE user_profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE tax_records ENABLE ROW LEVEL SECURITY;
ALTER TABLE suppliers ENABLE ROW LEVEL SECURITY;
ALTER TABLE invoices ENABLE ROW LEVEL SECURITY;
ALTER TABLE tax_documents ENABLE ROW LEVEL SECURITY;
ALTER TABLE gstr2b_records ENABLE ROW LEVEL SECURITY;
ALTER TABLE reconciliation_results ENABLE ROW LEVEL SECURITY;
ALTER TABLE audit_logs ENABLE ROW LEVEL SECURITY;
ALTER TABLE notifications ENABLE ROW LEVEL SECURITY;
ALTER TABLE sessions ENABLE ROW LEVEL SECURITY;

-- ============================================================================
-- USER_PROFILES RLS POLICIES
-- ============================================================================

-- Users can only view their own profile
CREATE POLICY "Users can view own profile" ON user_profiles
  FOR SELECT
  USING (auth_user_id = auth.uid());

-- Users can only update their own profile
CREATE POLICY "Users can update own profile" ON user_profiles
  FOR UPDATE
  USING (auth_user_id = auth.uid())
  WITH CHECK (auth_user_id = auth.uid());

-- Service role can create profiles (during registration)
CREATE POLICY "Service role can create profiles" ON user_profiles
  FOR INSERT
  WITH CHECK (TRUE);

-- ============================================================================
-- TAX_RECORDS RLS POLICIES
-- ============================================================================

-- Users can only see their own tax records
CREATE POLICY "Users can view own tax records" ON tax_records
  FOR SELECT
  USING (
    user_id = (
      SELECT id FROM user_profiles WHERE auth_user_id = auth.uid()
    )
  );

-- Users can create/update/delete only their own tax records
CREATE POLICY "Users can create own tax records" ON tax_records
  FOR INSERT
  WITH CHECK (
    user_id = (
      SELECT id FROM user_profiles WHERE auth_user_id = auth.uid()
    )
  );

CREATE POLICY "Users can update own tax records" ON tax_records
