-- Create bucket for encrypted invoice files
INSERT INTO storage.buckets (id, name, public)
VALUES ('invoice-files', 'invoice-files', false)
ON CONFLICT (id) DO NOTHING;

-- Create bucket for encrypted tax documents
INSERT INTO storage.buckets (id, name, public)
VALUES ('tax-documents', 'tax-documents', false)
ON CONFLICT (id) DO NOTHING;

-- RLS policies for storage buckets
-- Only users can access their own files

CREATE POLICY "Users can upload own invoice files" ON storage.objects
  FOR INSERT
  WITH CHECK (
    bucket_id = 'invoice-files' AND
    auth.uid() IS NOT NULL
  );

CREATE POLICY "Users can view own invoice files" ON storage.objects
  FOR SELECT
  USING (
    bucket_id = 'invoice-files' AND
    auth.uid() IS NOT NULL
  );

CREATE POLICY "Users can delete own invoice files" ON storage.objects
  FOR DELETE
  USING (
    bucket_id = 'invoice-files' AND
    auth.uid() IS NOT NULL
  );

CREATE POLICY "Users can upload own tax documents" ON storage.objects
  FOR INSERT
  WITH CHECK (
    bucket_id = 'tax-documents' AND
    auth.uid() IS NOT NULL
  );

CREATE POLICY "Users can view own tax documents" ON storage.objects
  FOR SELECT
  USING (
    bucket_id = 'tax-documents' AND
    auth.uid() IS NOT NULL
  );

CREATE POLICY "Users can delete own tax documents" ON storage.objects
  FOR DELETE
  USING (
    bucket_id = 'tax-documents' AND
    auth.uid() IS NOT NULL
  );

